1	package services
2	
3	import (
4		"database/sql"
5		"errors"
6		"fmt"
7	
8		"w2t86/internal/models"
9		"w2t86/internal/observability"
10		"w2t86/internal/repository"
11	)
12	
13	// IssueItem identifies a single material line to be physically issued.
14	type IssueItem struct {
15		MaterialID int64
16		Qty        int
17	}
18	
19	// DistributionService orchestrates all clerk-facing distribution operations:
20	// issuing, returning, exchanging, and reissuing physical copies.
21	type DistributionService struct {
22		distRepo     *repository.DistributionRepository
23		orderRepo    *repository.OrderRepository
24		materialRepo *repository.MaterialRepository
25	}
26	
27	// NewDistributionService wires the service to its three repositories.
28	func NewDistributionService(
29		dr *repository.DistributionRepository,
30		or *repository.OrderRepository,
31		mr *repository.MaterialRepository,
32	) *DistributionService {
33		return &DistributionService{
34			distRepo:     dr,
35			orderRepo:    or,
36			materialRepo: mr,
37		}
38	}
39	
40	// ---------------------------------------------------------------
41	// Issue
42	// ---------------------------------------------------------------
43	
44	// IssueItems records an "issued" distribution event for every item in the
45	// slice, marks the corresponding order_items as fulfilled, and — when all
46	// items for the order are fulfilled — advances the order status to in_transit.
47	//
48	// scanID is a barcode / copy identifier that binds the physical copy to the
49	// event.  It is shared across all items in a single issue batch.
50	func (s *DistributionService) IssueItems(orderID, actorID int64, scanID string, items []IssueItem) error {
51		if len(items) == 0 {
52			return errors.New("service: IssueItems: at least one item required")
53		}
54	
55		order, err := s.orderRepo.GetByID(orderID)
56		if err != nil {
57			if errors.Is(err, sql.ErrNoRows) {
58				return fmt.Errorf("service: IssueItems: order %d not found", orderID)
59			}
60			return fmt.Errorf("service: IssueItems: load order: %w", err)
61		}
62		if order.Status != "pending_shipment" && order.Status != "in_transit" {
63			return fmt.Errorf("service: IssueItems: order %d is not ready to issue (status=%s)", orderID, order.Status)
64		}
65	
66		scanIDPtr := &scanID
67		actorIDPtr := &actorID
68		orderIDPtr := &orderID
69	
70		for _, item := range items {
71			if item.Qty <= 0 {
72				return fmt.Errorf("service: IssueItems: qty must be positive for material %d", item.MaterialID)
73			}
74	
75			// Verify the material exists.
76			if _, err := s.materialRepo.GetByID(item.MaterialID); err != nil {
77				if errors.Is(err, sql.ErrNoRows) {
78					return fmt.Errorf("service: IssueItems: material %d not found", item.MaterialID)
79				}
80				return fmt.Errorf("service: IssueItems: load material %d: %w", item.MaterialID, err)
81			}
82	
83			evt := &models.DistributionEvent{
84				OrderID:     orderIDPtr,
85				MaterialID:  item.MaterialID,
86				Qty:         item.Qty,
87				EventType:   "issued",
88				ScanID:      scanIDPtr,
89				ActorID:     actorIDPtr,
90				CustodyFrom: stringPtr("clerk"),
91				CustodyTo:   stringPtr("student"),
92			}
93			if _, err := s.distRepo.RecordEvent(evt); err != nil {
94				return fmt.Errorf("service: IssueItems: record event for material %d: %w", item.MaterialID, err)
95			}
96		}
97	
98		// Mark order items as fulfilled and potentially advance order status.
99		if err := s.markItemsFulfilled(orderID, actorID, items); err != nil {
100			return fmt.Errorf("service: IssueItems: mark fulfilled: %w", err)
101		}
102	
103		observability.Distribution.Info("items issued", "order_id", orderID, "scan_id", scanID, "item_count", len(items))
104		return nil
105	}
106	
107	// markItemsFulfilled sets fulfillment_status='fulfilled' for each issued item
108	// and advances the order to in_transit if it was previously pending_shipment.
109	// Once all items are fulfilled the order moves to completed.
110	func (s *DistributionService) markItemsFulfilled(orderID, actorID int64, items []IssueItem) error {
111		for _, item := range items {
112			const q = `
113				UPDATE order_items
114				SET    fulfillment_status = 'fulfilled'
115				WHERE  order_id = ? AND material_id = ? AND fulfillment_status = 'pending'`
116			if _, err := s.orderRepo.DB().Exec(q, orderID, item.MaterialID); err != nil {
117				return fmt.Errorf("markItemsFulfilled: update order_item: %w", err)
118			}
119		}
120	
121		// Advance order from pending_shipment → in_transit on first issue.
122		order, err := s.orderRepo.GetByID(orderID)
123		if err != nil {
124			return err
125		}
126		if order.Status == "pending_shipment" {
127			if err := s.orderRepo.Transition(orderID, actorID, "in_transit", "items issued by clerk", s.materialRepo); err != nil {
128				return fmt.Errorf("markItemsFulfilled: advance to in_transit: %w", err)
129			}
130		}
131	
132		return nil
133	}
134	
135	// ---------------------------------------------------------------
136	// Return
137	// ---------------------------------------------------------------
138	
139	// RecordReturn records a "returned" distribution event and releases inventory
140	// (increments available_qty by qty).
141	func (s *DistributionService) RecordReturn(orderID, materialID, actorID int64, scanID string, qty int) error {
142		if qty <= 0 {
143			return errors.New("service: RecordReturn: qty must be positive")
144		}
145	
146		// Verify order exists.
147		if _, err := s.orderRepo.GetByID(orderID); err != nil {
148			if errors.Is(err, sql.ErrNoRows) {
149				return fmt.Errorf("service: RecordReturn: order %d not found", orderID)
150			}
151			return fmt.Errorf("service: RecordReturn: load order: %w", err)
152		}
153	
154		orderIDPtr := &orderID
155		actorIDPtr := &actorID
156		scanIDPtr := &scanID
157	
158		evt := &models.DistributionEvent{
159			OrderID:     orderIDPtr,
160			MaterialID:  materialID,
161			Qty:         qty,
162			EventType:   "returned",
163			ScanID:      scanIDPtr,
164			ActorID:     actorIDPtr,
165			CustodyFrom: stringPtr("student"),
166			CustodyTo:   stringPtr("clerk"),
167		}
168		if _, err := s.distRepo.RecordEvent(evt); err != nil {
169			return fmt.Errorf("service: RecordReturn: record event: %w", err)
170		}
171	
172		// Release inventory.
173		const q = `
174			UPDATE materials
175			SET    available_qty = available_qty + ?,
176			       updated_at    = datetime('now')
177			WHERE  id = ?`
178		if _, err := s.materialRepo.DB().Exec(q, qty, materialID); err != nil {
179			return fmt.Errorf("service: RecordReturn: release inventory: %w", err)
180		}
181	
182		observability.Distribution.Info("item returned", "scan_id", scanID, "qty", qty)
183		return nil
184	}
185	
186	// ---------------------------------------------------------------
187	// Exchange
188	// ---------------------------------------------------------------
189	
190	// RecordExchange swaps an old copy for a new one in a single logical operation:
191	//  1. Records a "returned" event for oldMaterialID.
192	//  2. Verifies the new material has available stock.
193	//  3. Records an "issued" event for newMaterialID and decrements its
194	//     available_qty.
195	func (s *DistributionService) RecordExchange(orderID, oldMaterialID, newMaterialID, actorID int64, scanID string, qty int) error {
196		if qty <= 0 {
197			return errors.New("service: RecordExchange: qty must be positive")
198		}
199	
200		// Return the old copy first (releases its inventory).
201		if err := s.RecordReturn(orderID, oldMaterialID, actorID, scanID, qty); err != nil {
202			return fmt.Errorf("service: RecordExchange: return old: %w", err)
203		}
204	
205		// Check new material stock.
206		newMat, err := s.materialRepo.GetByID(newMaterialID)
207		if err != nil {
208			if errors.Is(err, sql.ErrNoRows) {
209				return fmt.Errorf("service: RecordExchange: new material %d not found", newMaterialID)
210			}
211			return fmt.Errorf("service: RecordExchange: load new material: %w", err)
212		}
213		if newMat.AvailableQty < qty {
214			return fmt.Errorf("service: RecordExchange: insufficient stock for material %q (available %d, requested %d)",
215				newMat.Title, newMat.AvailableQty, qty)
216		}
217	
218		orderIDPtr := &orderID
219		actorIDPtr := &actorID
220		newScanID := scanID + "_exch"
221		scanIDPtr := &newScanID
222	
223		evt := &models.DistributionEvent{
224			OrderID:     orderIDPtr,
225			MaterialID:  newMaterialID,
226			Qty:         qty,
227			EventType:   "issued",
228			ScanID:      scanIDPtr,
229			ActorID:     actorIDPtr,
230			CustodyFrom: stringPtr("clerk"),
231			CustodyTo:   stringPtr("student"),
232		}
233		if _, err := s.distRepo.RecordEvent(evt); err != nil {
234			return fmt.Errorf("service: RecordExchange: record issue event: %w", err)
235		}
236	
237		// Decrement available_qty for the newly issued material.
238		const q = `
239			UPDATE materials
240			SET    available_qty = available_qty - ?,
241			       updated_at    = datetime('now')
242			WHERE  id = ? AND available_qty >= ?`
243		res, err := s.materialRepo.DB().Exec(q, qty, newMaterialID, qty)
244		if err != nil {
245			return fmt.Errorf("service: RecordExchange: decrement new material inventory: %w", err)
246		}
247		if n, _ := res.RowsAffected(); n == 0 {
248			return fmt.Errorf("service: RecordExchange: stock changed during exchange for material %d", newMaterialID)
249		}
250	
251		return nil
252	}
253	
254	
255	// ---------------------------------------------------------------
256	// Reissue
257	// ---------------------------------------------------------------
258	
259	// ReissueItem handles lost or damaged copy replacement:
260	//   - Records a "lost" or "damaged" event for oldScanID (marking it out of
261	//     circulation).
262	//   - Records a new "issued" event for newScanID.
263	//
264	// reason must be "lost" or "damaged".
265	func (s *DistributionService) ReissueItem(orderID, materialID, actorID int64, oldScanID, newScanID, reason string) error {
266		if reason != "lost" && reason != "damaged" {
267			return fmt.Errorf("service: ReissueItem: invalid reason %q (must be 'lost' or 'damaged')", reason)
268		}
269		if oldScanID == "" || newScanID == "" {
270			return errors.New("service: ReissueItem: both oldScanID and newScanID are required")
271		}
272	
273		// Verify order exists.
274		if _, err := s.orderRepo.GetByID(orderID); err != nil {
275			if errors.Is(err, sql.ErrNoRows) {
276				return fmt.Errorf("service: ReissueItem: order %d not found", orderID)
277			}
278			return fmt.Errorf("service: ReissueItem: load order: %w", err)
279		}
280	
281		orderIDPtr := &orderID
282		actorIDPtr := &actorID
283	
284		// Record the loss/damage event for the old scan ID.
285		oldEvt := &models.DistributionEvent{
286			OrderID:    orderIDPtr,
287			MaterialID: materialID,
288			Qty:        1,
289			EventType:  reason, // "lost" or "damaged"
290			ScanID:     &oldScanID,
291			ActorID:    actorIDPtr,
292		}
293		if _, err := s.distRepo.RecordEvent(oldEvt); err != nil {
294			return fmt.Errorf("service: ReissueItem: record %s event: %w", reason, err)
295		}
296	
297		// Issue the replacement copy.
298		newEvt := &models.DistributionEvent{
299			OrderID:     orderIDPtr,
300			MaterialID:  materialID,
301			Qty:         1,
302			EventType:   "issued",
303			ScanID:      &newScanID,
304			ActorID:     actorIDPtr,
305			CustodyFrom: stringPtr("clerk"),
306			CustodyTo:   stringPtr("student"),
307		}
308		if _, err := s.distRepo.RecordEvent(newEvt); err != nil {
309			return fmt.Errorf("service: ReissueItem: record replacement issue event: %w", err)
310		}
311	
312		observability.Distribution.Info("item reissued", "old_scan_id", oldScanID, "new_scan_id", newScanID, "reason", reason)
313		return nil
314	}
315	
316	// ---------------------------------------------------------------
317	// Ledger / chain queries — thin pass-through
318	// ---------------------------------------------------------------
319	
320	// GetLedger returns a paginated, filtered view of distribution events.
321	func (s *DistributionService) GetLedger(filters repository.DistributionFilter, limit, offset int) ([]models.DistributionEvent, error) {
322		return s.distRepo.ListEvents(filters, limit, offset)
323	}
324	
325	// GetCustodyChain returns the full event history for a physical copy.
326	func (s *DistributionService) GetCustodyChain(scanID string) ([]models.DistributionEvent, error) {
327		if scanID == "" {
328			return nil, errors.New("service: GetCustodyChain: scanID is required")
329		}
330		return s.distRepo.GetCustodyChain(scanID)
331	}
332	
333	// GetPendingIssues returns the clerk's pick list.
334	func (s *DistributionService) GetPendingIssues(limit, offset int) ([]repository.PendingIssue, error) {
335		return s.distRepo.GetPendingIssues(limit, offset)
336	}
337	
338	// CountBackorders returns the total number of unresolved backorder records.
339	func (s *DistributionService) CountBackorders() (int, error) {
340		return s.distRepo.CountBackorders()
341	}
342	
343	// ---------------------------------------------------------------
344	// helpers
345	// ---------------------------------------------------------------
346	
347	func stringPtr(s string) *string { return &s }
348	
