70	// TestRateLimit_UnderLimit_AllAllowed: 4 requests with limit=5 → all pass.
71	func TestRateLimit_UnderLimit_AllAllowed(t *testing.T) {
72		app := fixedKeyApp(5, time.Minute, "under-limit")
73	
74		for i := 1; i <= 4; i++ {
75			if code := rlGet(t, app); code != fiber.StatusOK {
76				t.Errorf("request %d: expected 200, got %d", i, code)
77			}
78		}
