165	// TestRateLimit_ConcurrentRequests_ThreadSafe: 20 goroutines hammer the limiter
166	// concurrently. The test verifies no race condition or panic occurs, and that
167	// the number of allowed requests does not exceed the per-key limit.
168	func TestRateLimit_ConcurrentRequests_ThreadSafe(t *testing.T) {
169		const limit = 5
170		// 4 distinct keys so each key can pass at most limit requests.
171		const numKeys = 4
172		app := headerKeyApp(limit, time.Minute)
173	
174		var (
175			wg      sync.WaitGroup
176			allowed atomic.Int32
177		)
178		const goroutines = 20
179	
180		for i := 0; i < goroutines; i++ {
181			wg.Add(1)
182			go func(n int) {
183				defer wg.Done()
184				key := fmt.Sprintf("concurrent-key-%d", n%numKeys)
185				req := httptest.NewRequest("GET", "/", nil)
186				req.Header.Set("X-Key", key)
187				resp, err := app.Test(req, -1)
188				if err != nil {
189					return
190				}
191				io.Copy(io.Discard, resp.Body) //nolint:errcheck
192				resp.Body.Close()
193				if resp.StatusCode == fiber.StatusOK {
194					allowed.Add(1)
195				}
196			}(i)
197		}
198		wg.Wait()
199	
200		got := int(allowed.Load())
201		// At most numKeys*limit requests can be allowed.
202		maxAllowed := numKeys * limit
203		if got > maxAllowed {
204			t.Errorf("concurrent: allowed %d requests, expected at most %d (keys=%d, limit=%d)",
205				got, maxAllowed, numKeys, limit)
206		}
207		t.Logf("concurrent test: %d/%d requests allowed (max %d)", got, goroutines, maxAllowed)
208	}
