// ---------------------------------------------------------------------------
// loginAs creates a user with the given role and returns the session cookie.
// ---------------------------------------------------------------------------

func loginAs(t *testing.T, app *fiber.App, db *sql.DB, role string) string {
	t.Helper()
	username := fmt.Sprintf("api_user_%s_%d", role, time.Now().UnixNano())
	password := "TestPassword123!"
	email := username + "@example.com"

	userRepo := repository.NewUserRepository(db)
	sessionRepo := repository.NewSessionRepository(db)
	cfg := &config.Config{SessionSecret: "test-secret"}
	authSvc := services.NewAuthService(userRepo, sessionRepo, cfg)

	if _, err := authSvc.Register(username, email, password, role); err != nil {
		t.Fatalf("loginAs: register: %v", err)
	}

	body := fmt.Sprintf("username=%s&password=%s", username, password)
	req := httptest.NewRequest(http.MethodPost, "/login", strings.NewReader(body))
	req.Header.Set("Content-Type", "application/x-www-form-urlencoded")
	resp, err := app.Test(req, -1)
	if err != nil {
		t.Fatalf("loginAs: app.Test: %v", err)
	}
	defer resp.Body.Close()

	if resp.StatusCode != http.StatusFound && resp.StatusCode != http.StatusOK {
		b, _ := io.ReadAll(resp.Body)
		t.Fatalf("loginAs: unexpected status %d; body: %s", resp.StatusCode, string(b))
	}
	for _, c := range resp.Cookies() {
		if c.Name == "session_token" {
			return "session_token=" + c.Value
		}
	}
	t.Fatal("loginAs: no session_token cookie")
	return ""
}

// ---------------------------------------------------------------------------
// makeRequest fires a request and returns the response.
// ---------------------------------------------------------------------------

func makeRequest(app *fiber.App, method, path, body, cookie, contentType string, extra ...map[string]string) *http.Response {
	var br io.Reader
	if body != "" {
		br = strings.NewReader(body)
	}
	req := httptest.NewRequest(method, path, br)
	if cookie != "" {
		req.Header.Set("Cookie", cookie)
	}
	if contentType != "" {
		req.Header.Set("Content-Type", contentType)
	}
	for _, h := range extra {
		for k, v := range h {
			req.Header.Set(k, v)
		}
	}
	resp, err := app.Test(req, -1)
	if err != nil {
		return &http.Response{StatusCode: http.StatusInternalServerError}
	}
	return resp
}

// htmx returns a map with HX-Request: true for HTMX requests.
func htmx() map[string]string { return map[string]string{"HX-Request": "true"} }

// readBody drains and returns the response body as a string.
func readBody(resp *http.Response) string {
	if resp == nil || resp.Body == nil {
		return ""
	}
	defer resp.Body.Close()
	b, _ := io.ReadAll(resp.Body)
	return string(b)
}

// createMaterial inserts an active material and returns it.
func createMaterial(t *testing.T, db *sql.DB) *models.Material {
	t.Helper()
	repo := repository.NewMaterialRepository(db)
	m := &models.Material{
		Title:        fmt.Sprintf("API Test Book %d", time.Now().UnixNano()),
		TotalQty:     10,
		AvailableQty: 10,
		ReservedQty:  0,
		Status:       "active",
	}
	created, err := repo.Create(m)
	if err != nil {
		t.Fatalf("createMaterial: %v", err)
	}
	return created
}

// createUser registers a user and returns the model.
func createUser(t *testing.T, db *sql.DB, role string) *models.User {
	t.Helper()
	username := fmt.Sprintf("api_cu_%s_%d", role, time.Now().UnixNano())
	userRepo := repository.NewUserRepository(db)
	sessionRepo := repository.NewSessionRepository(db)
	cfg := &config.Config{SessionSecret: "test-secret"}
	svc := services.NewAuthService(userRepo, sessionRepo, cfg)
	user, err := svc.Register(username, username+"@x.com", "TestPassword123!", role)
	if err != nil {
		t.Fatalf("createUser: %v", err)
	}
	return user
}
"}

