1	package handlers
2	
3	import (
4		"fmt"
5		"strconv"
6	
7		"github.com/gofiber/fiber/v2"
8	
9		"w2t86/internal/middleware"
10		"w2t86/internal/models"
11		"w2t86/internal/observability"
12		"w2t86/internal/services"
13	)
14	
15	// MaterialHandler handles all materials-related HTTP routes.
16	type MaterialHandler struct {
17		materialService *services.MaterialService
18		authMiddleware  *middleware.AuthMiddleware
19	}
20	
21	// NewMaterialHandler creates a MaterialHandler backed by the given service.
22	func NewMaterialHandler(ms *services.MaterialService) *MaterialHandler {
23		return &MaterialHandler{materialService: ms}
24	}
25	
26	// ---------------------------------------------------------------
27	// Public / student routes
28	// ---------------------------------------------------------------
29	
30	// ListPage handles GET /materials — renders the full materials search page.
31	func (h *MaterialHandler) ListPage(c *fiber.Ctx) error {
32		user := middleware.GetUser(c)
33		return c.Render("materials/list", fiber.Map{
34			"Title": "Materials Catalog",
35			"User":  user,
36		}, "layouts/main")
37	}
38	
39	// SearchPartial handles GET /materials/search — HTMX partial returning material cards.
40	// Accepts query params: q, subject, grade.
41	func (h *MaterialHandler) SearchPartial(c *fiber.Ctx) error {
42		q := c.Query("q")
43		subject := c.Query("subject")
44		grade := c.Query("grade")
45	
46		limit := 24
47		offset := 0
48		if p := c.QueryInt("page", 1); p > 1 {
49			offset = (p - 1) * limit
50		}
51	
52		filters := map[string]string{}
53		if subject != "" {
54			filters["subject"] = subject
55		}
56		if grade != "" {
57			filters["grade_level"] = grade
58		}
59	
60		materials, err := h.materialService.Search(q, filters, limit, offset)
61		if err != nil {
62			return internalErr(c, observability.App, "material search failed", err, "query", q)
63		}
64	
65		return c.Render("partials/material_cards", fiber.Map{
66			"Materials": materials,
67			"Query":     q,
68		})
69	}
70	
71	// DetailPage handles GET /materials/:id — renders the full material detail page.
72	// Records browse history for authenticated users.
73	func (h *MaterialHandler) DetailPage(c *fiber.Ctx) error {
74		id, err := c.ParamsInt("id")
75		if err != nil {
76			return apiErr(c, fiber.StatusBadRequest, "Invalid material ID")
77		}
78	
79		material, err := h.materialService.GetByID(int64(id))
80		if err != nil {
81			return c.Status(fiber.StatusNotFound).Render("materials/detail", fiber.Map{
82				"Title": "Not Found",
83				"Error": "Material not found",
84			}, "layouts/main")
85		}
86	
87		user := middleware.GetUser(c)
88	
89		// Best-effort browse history recording (non-fatal).
90		if user != nil {
91			if err := h.materialService.RecordVisit(int64(id), user.ID); err != nil {
92				observability.App.Warn("record visit failed", "material_id", id, "user_id", user.ID, "error", err)
93			}
94		}
95	
96		// Load average rating and user's own rating.
97		avgRating, ratingCount, err := h.materialService.GetAverageRating(int64(id))
98		if err != nil {
99			observability.App.Warn("get average rating failed", "material_id", id, "error", err)
100			avgRating, ratingCount = 0, 0
101		}
102		var userStars int
103		if user != nil {
104			userStars, err = h.materialService.GetUserRating(int64(id), user.ID)
105			if err != nil {
106				observability.App.Warn("get user rating failed", "material_id", id, "user_id", user.ID, "error", err)
107				userStars = 0
108			}
109		}
110	
111		// Load comments (include collapsed for the owner / admin; exclude for others).
112		includeCollapsed := user != nil && (user.Role == "admin" || user.Role == "moderator")
113		comments, err := h.materialService.GetComments(int64(id), includeCollapsed, 50, 0)
114		if err != nil {
115			observability.App.Warn("get comments failed", "material_id", id, "error", err)
116			comments = nil
117		}
118	
119		return c.Render("materials/detail", fiber.Map{
120			"Title":       material.Title,
121			"Material":    material,
122			"User":        user,
123			"AvgRating":   fmt.Sprintf("%.1f", avgRating),
124			"RatingCount": ratingCount,
125			"UserStars":   userStars,
126			"Comments":    comments,
127		}, "layouts/main")
128	}
129	
130	// Rate handles POST /materials/:id/rate — records a star rating via HTMX.
131	func (h *MaterialHandler) Rate(c *fiber.Ctx) error {
132		id, err := c.ParamsInt("id")
133		if err != nil {
134			return apiErr(c, fiber.StatusBadRequest, "Invalid material ID")
135		}
136	
137		user := middleware.GetUser(c)
138		if user == nil {
139			observability.Security.Warn("unauthenticated access attempt", "path", c.Path(), "ip", c.IP())
140			return apiErr(c, fiber.StatusUnauthorized, "Authentication required")
141		}
142	
143		starsStr := c.FormValue("stars")
144		stars, err := strconv.Atoi(starsStr)
145		if err != nil || stars < 1 || stars > 5 {
146			return htmxErr(c, fiber.StatusBadRequest, "Stars must be between 1 and 5")
147		}
148	
149		if err := h.materialService.Rate(int64(id), user.ID, stars); err != nil {
150			return internalErr(c, observability.App, "rate material failed", err, "material_id", id, "user_id", user.ID)
151		}
152	
153		avg, count, err := h.materialService.GetAverageRating(int64(id))
154		if err != nil {
155			observability.App.Warn("get average rating failed", "material_id", id, "error", err)
156			avg, count = 0, 0
157		}
158	
159		if c.Get("HX-Request") == "true" {
160			return c.Render("partials/star_widget", fiber.Map{
161				"MaterialID":  id,
162				"AvgRating":   fmt.Sprintf("%.1f", avg),
163				"RatingCount": count,
164				"UserStars":   stars,
165			})
166		}
167		return c.Redirect(fmt.Sprintf("/materials/%d", id), fiber.StatusFound)
168	}
169	
170	// AddComment handles POST /materials/:id/comments — posts a comment via HTMX.
171	func (h *MaterialHandler) AddComment(c *fiber.Ctx) error {
172		id, err := c.ParamsInt("id")
173		if err != nil {
174			return apiErr(c, fiber.StatusBadRequest, "Invalid material ID")
175		}
176	
177		user := middleware.GetUser(c)
178		if user == nil {
179			observability.Security.Warn("unauthenticated access attempt", "path", c.Path(), "ip", c.IP())
180			return apiErr(c, fiber.StatusUnauthorized, "Authentication required")
181		}
182	
183		body := c.FormValue("body")
184	
185		comment, err := h.materialService.AddComment(int64(id), user.ID, body)
186		if err != nil {
187			// The service returns user-facing validation errors for rate limit and
188			// sensitive words. Log the specific cause then return a fixed message.
189			observability.App.Warn("add comment rejected", "material_id", id, "user_id", user.ID, "error", err)
190			if c.Get("HX-Request") == "true" {
191				return c.Status(fiber.StatusUnprocessableEntity).Render("partials/comment_form", fiber.Map{
192					"MaterialID": id,
193					"Error":      "Your comment could not be submitted. Please check your input and try again.",
194					"Body":       body,
195				})
196			}
197			return htmxErr(c, fiber.StatusUnprocessableEntity, "Your comment could not be submitted. Please check your input and try again.")
198		}
199	
200		if c.Get("HX-Request") == "true" {
201			comments, err := h.materialService.GetComments(int64(id), false, 50, 0)
202			if err != nil {
203				observability.App.Warn("get comments failed after add", "material_id", id, "error", err)
204				comments = nil
205			}
206			return c.Render("partials/comments_list", fiber.Map{
207				"MaterialID": id,
208				"Comments":   comments,
209				"NewComment": comment,
210				"User":       user,
211			})
212		}
213		return c.Redirect(fmt.Sprintf("/materials/%d", id), fiber.StatusFound)
214	}
215	
216	// ReportComment handles POST /comments/:id/report — reports a comment via HTMX.
217	func (h *MaterialHandler) ReportComment(c *fiber.Ctx) error {
218		commentID, err := c.ParamsInt("id")
219		if err != nil {
220			return apiErr(c, fiber.StatusBadRequest, "Invalid comment ID")
221		}
222	
223		user := middleware.GetUser(c)
224		if user == nil {
225			observability.Security.Warn("unauthenticated access attempt", "path", c.Path(), "ip", c.IP())
226			return apiErr(c, fiber.StatusUnauthorized, "Authentication required")
227		}
228	
229		reason := c.FormValue("reason")
230	
231		if err := h.materialService.ReportComment(int64(commentID), user.ID, reason); err != nil {
232			return internalErr(c, observability.App, "report comment failed", err, "comment_id", commentID, "user_id", user.ID)
233		}
234	
235		if c.Get("HX-Request") == "true" {
236			return c.Render("partials/comment_reported", fiber.Map{
237				"CommentID": commentID,
238				"Message":   "Report submitted. Thank you.",
239			})
240		}
241		return c.JSON(fiber.Map{"msg": "Report submitted"})
242	}
