244	// ---------------------------------------------------------------
245	// Admin routes
246	// ---------------------------------------------------------------
247	
248	// NewMaterialForm handles GET /admin/materials/new.
249	func (h *MaterialHandler) NewMaterialForm(c *fiber.Ctx) error {
250		return c.Render("admin/materials/new", fiber.Map{
251			"Title": "Add Material",
252			"User":  middleware.GetUser(c),
253		}, "layouts/main")
254	}
255	
256	// CreateMaterial handles POST /admin/materials.
257	func (h *MaterialHandler) CreateMaterial(c *fiber.Ctx) error {
258		user := middleware.GetUser(c)
259	
260		m := materialModelFromForm(c)
261	
262		created, err := h.materialService.CreateMaterial(m, user.ID)
263		if err != nil {
264			observability.App.Warn("create material rejected", "user_id", user.ID, "error", err)
265			data := fiber.Map{
266				"Title":    "Add Material",
267				"Error":    "Could not create material. Please check your input and try again.",
268				"Material": m,
269				"User":     user,
270			}
271			if c.Get("HX-Request") == "true" {
272				return c.Status(fiber.StatusUnprocessableEntity).Render("admin/materials/new", data)
273			}
274			return c.Status(fiber.StatusUnprocessableEntity).Render("admin/materials/new", data, "layouts/main")
275		}
276	
277		return c.Redirect(fmt.Sprintf("/materials/%d", created.ID), fiber.StatusFound)
278	}
