308	
309		if err := h.materialService.UpdateMaterial(int64(id), fields, user.ID); err != nil {
310			return internalErr(c, observability.App, "update material failed", err, "material_id", id, "user_id", user.ID)
311		}
312	
313		if c.Get("HX-Request") == "true" {
314			return c.Render("partials/flash", fiber.Map{"Message": "Material updated successfully."})
315		}
316		return c.Redirect(fmt.Sprintf("/materials/%d", id), fiber.StatusFound)
