106	// Update applies the given field map to the user identified by id.
107	// Only columns present in the map are changed; updated_at is always refreshed.
108	// Allowed keys: username, email, password_hash, role.
109	func (r *UserRepository) Update(id int64, fields map[string]interface{}) error {
110		if len(fields) == 0 {
111			return nil
112		}
113	
114		allowed := map[string]bool{
115			"username":      true,
116			"email":         true,
117			"password_hash": true,
118			"role":          true,
119		}
120	
121		setClauses := make([]string, 0, len(fields)+1)
122		args := make([]interface{}, 0, len(fields)+2)
123	
124		for col, val := range fields {
125			if !allowed[col] {
126				return fmt.Errorf("repository: Update: unknown or disallowed column %q", col)
127			}
128			setClauses = append(setClauses, col+" = ?")
129			args = append(args, val)
130		}
131		setClauses = append(setClauses, "updated_at = datetime('now')")
132		args = append(args, id)
133	
134		q := "UPDATE users SET " + strings.Join(setClauses, ", ") + " WHERE id = ? AND deleted_at IS NULL"
135		_, err := r.db.Exec(q, args...)
136		return err
137	}
