139	// SoftDelete sets deleted_at on the user row.
140	func (r *UserRepository) SoftDelete(id int64) error {
141		const q = `UPDATE users SET deleted_at = datetime('now'), updated_at = datetime('now') WHERE id = ? AND deleted_at IS NULL`
142		_, err := r.db.Exec(q, id)
143		return err
144	}
