{"replace_all": false, "file_path": "/Users/rollin/eaglepoint/w2t86/repo/internal/repository/admin.go", "old_string": "// FindDuplicateUsers returns user pairs whose usernames share a common 4-character
// prefix (case-insensitive), excluding soft-deleted users.
// The Score is approximated as 1 - (length_diff / max_len).
func (r *AdminRepository) FindDuplicateUsers(limit int) ([]DuplicatePair, error) {
	// Self-join: find pairs where the first 4 chars of username match.
	// We use LOWER(SUBSTR(username,1,4)) as the joining key.
	const q = `
		SELECT a.id, a.username, a.email, a.password_hash, a.role,
		       a.failed_attempts, a.locked_until, a.created_at, a.updated_at, a.deleted_at,
		       b.id, b.username, b.email, b.password_hash, b.role,
		       b.failed_attempts, b.locked_until, b.created_at, b.updated_at, b.deleted_at
		FROM   users a
		JOIN   users b ON b.id > a.id
		             AND LOWER(SUBSTR(b.username,1,4)) = LOWER(SUBSTR(a.username,1,4))
		WHERE  a.deleted_at IS NULL
		  AND  b.deleted_at IS NULL
		ORDER  BY a.id
		LIMIT  ?`

	rows, err := r.db.Query(q, limit)
	if err != nil {
		return nil, fmt.Errorf("repository: FindDuplicateUsers: %w", err)
	}
	defer rows.Close()

	var pairs []DuplicatePair
	for rows.Next() {
		var p DuplicatePair
		a := &p.UserA
		b := &p.UserB
		if err := rows.Scan(
			&a.ID, &a.Username, &a.Email, &a.PasswordHash, &a.Role,
			&a.FailedAttempts, &a.LockedUntil, &a.CreatedAt, &a.UpdatedAt, &a.DeletedAt,
			&b.ID, &b.Username, &b.Email, &b.PasswordHash, &b.Role,
			&b.FailedAttempts, &b.LockedUntil, &b.CreatedAt, &b.UpdatedAt, &b.DeletedAt,
		); err != nil {
			return nil, fmt.Errorf("repository: FindDuplicateUsers: scan: %w", err)
		}
		// Simple similarity: prefix match gives at least 4 chars shared.
		lenA := len(p.UserA.Username)
		lenB := len(p.UserB.Username)
		maxLen := lenA
		if lenB > maxLen {
			maxLen = lenB
		}
		diff := lenA - lenB
		if diff < 0 {
			diff = -diff
		}
		if maxLen > 0 {
			p.Score = 1.0 - float64(diff)/float64(maxLen)
		} else {
			p.Score = 1.0
		}
		pairs = append(pairs, p)
	}
	return pairs, rows.Err()
}", "new_string": "// FindDuplicateUsers returns user pairs that are likely the same person.
// Two detection strategies are applied (highest score wins):
//  1. Exact email match → score 1.0 (definite duplicate).
//  2. Same date_of_birth + matching 4-char username prefix → score 0.7.
//
// Soft-deleted users are excluded.
func (r *AdminRepository) FindDuplicateUsers(limit int) ([]DuplicatePair, error) {
	const q = `
		SELECT a.id, a.username, a.email, a.password_hash, a.role,
		       a.failed_attempts, a.locked_until, a.date_of_birth,
		       a.created_at, a.updated_at, a.deleted_at,
		       b.id, b.username, b.email, b.password_hash, b.role,
		       b.failed_attempts, b.locked_until, b.date_of_birth,
		       b.created_at, b.updated_at, b.deleted_at,
		       CASE WHEN a.email = b.email THEN 1.0 ELSE 0.7 END AS score
		FROM   users a
		JOIN   users b ON b.id > a.id
		WHERE  a.deleted_at IS NULL
		  AND  b.deleted_at IS NULL
		  AND (
		        a.email = b.email
		        OR (
		              a.date_of_birth IS NOT NULL
		          AND a.date_of_birth = b.date_of_birth
		          AND LOWER(SUBSTR(a.username,1,4)) = LOWER(SUBSTR(b.username,1,4))
		        )
		      )
		ORDER  BY score DESC, a.id
		LIMIT  ?`

	rows, err := r.db.Query(q, limit)
	if err != nil {
		return nil, fmt.Errorf("repository: FindDuplicateUsers: %w", err)
	}
	defer rows.Close()

	var pairs []DuplicatePair
	for rows.Next() {
		var p DuplicatePair
		a := &p.UserA
		b := &p.UserB
		if err := rows.Scan(
			&a.ID, &a.Username, &a.Email, &a.PasswordHash, &a.Role,
			&a.FailedAttempts, &a.LockedUntil, &a.DateOfBirth,
			&a.CreatedAt, &a.UpdatedAt, &a.DeletedAt,
			&b.ID, &b.Username, &b.Email, &b.PasswordHash, &b.Role,
			&b.FailedAttempts, &b.LockedUntil, &b.DateOfBirth,
			&b.CreatedAt, &b.UpdatedAt, &b.DeletedAt,
			&p.Score,
		); err != nil {
			return nil, fmt.Errorf("repository: FindDuplicateUsers: scan: %w", err)
		}
		pairs = append(pairs, p)
	}
	return pairs, rows.Err()
}"}

