147	// geoJSONFeature is the internal representation of a GeoJSON Feature.
148	type geoJSONFeature struct {
149		Type     string                 `json:"type"`
150		Geometry geoJSONGeometry        `json:"geometry"`
151		Props    map[string]interface{} `json:"properties"`
152	}
153	
154	type geoJSONGeometry struct {
155		Type        string    `json:"type"`
156		Coordinates []float64 `json:"coordinates"`
157	}
158	
159	type geoJSONCollection struct {
160		Type     string           `json:"type"`
161		Features []geoJSONFeature `json:"features"`
162	}
163	
164	// locationsToGeoJSON converts a slice of Location rows into a GeoJSON
165	// FeatureCollection string.  Locations without lat/lng are skipped.
166	func locationsToGeoJSON(locations []models.Location) string {
167		features := make([]geoJSONFeature, 0, len(locations))
168		for _, loc := range locations {
169			if loc.Lat == nil || loc.Lng == nil {
170				continue
171			}
172			props := map[string]interface{}{
173				"id":   loc.ID,
174				"name": loc.Name,
175			}
176			if loc.Type != nil {
177				props["type"] = *loc.Type
178			}
179			if loc.Properties != nil {
180				// Attempt to merge the stored JSON properties blob.
181				var extra map[string]interface{}
182				if err := json.Unmarshal([]byte(*loc.Properties), &extra); err == nil {
183					for k, v := range extra {
184						props[k] = v
185					}
186				} else {
187					props["properties"] = *loc.Properties
188				}
189			}
190			features = append(features, geoJSONFeature{
191				Type: "Feature",
192				Geometry: geoJSONGeometry{
193					Type:        "Point",
194					Coordinates: []float64{*loc.Lng, *loc.Lat}, // GeoJSON order: [lng, lat]
195				},
196				Props: props,
197			})
198		}
199	
200		col := geoJSONCollection{
201			Type:     "FeatureCollection",
202			Features: features,
203		}
204		b, err := json.Marshal(col)
205		if err != nil {
206			return `{"type":"FeatureCollection","features":[]}`
207		}
208		return string(b)
209	}
