233		var buf bytes.Buffer
234		w := csv.NewWriter(&buf)
235	
236		// Header
237		if err := w.Write([]string{
238			"order_id", "user_name", "user_email", "status",
239			"total_amount", "created_at", "item_count",
240		}); err != nil {
241			return nil, fmt.Errorf("service: ExportOrdersCSV: write header: %w", err)
242		}
243	
244		for _, row := range rows {
245			record := []string{
246				strconv.FormatInt(row.OrderID, 10),
247				crypto.MaskName(row.UserName),
248				crypto.MaskID(row.UserEmail),
249				row.Status,
250				strconv.FormatFloat(row.TotalAmount, 'f', 2, 64),
251				row.CreatedAt,
252				strconv.Itoa(row.ItemCount),
253			}
254			if err := w.Write(record); err != nil {
255				return nil, fmt.Errorf("service: ExportOrdersCSV: write row: %w", err)
256			}
257		}
258	
259		w.Flush()
260		if err := w.Error(); err != nil {
261			return nil, fmt.Errorf("service: ExportOrdersCSV: flush: %w", err)
262		}
263		return buf.Bytes(), nil
264	}
