// Two detection strategies are applied:
//  1. Exact email match → score 1.0 (definite duplicate).
//  2. Same date_of_birth (non-null) + Levenshtein username similarity ≥ 0.6
//     → score equal to the computed similarity (fuzzy match).
//
// Results are sorted by descending score, capped at limit.
// Soft-deleted users are excluded.
func (r *AdminRepository) FindDuplicateUsers(limit int) ([]DuplicatePair, error) {
	// ---- Pass 1: exact email duplicates (score 1.0) ----
	const exactQ = `
		SELECT a.id, a.username, a.email, a.password_hash, a.role,
		       a.failed_attempts, a.locked_until, a.date_of_birth,
		       a.created_at, a.updated_at, a.deleted_at,
		       b.id, b.username, b.email, b.password_hash, b.role,
		       b.failed_attempts, b.locked_until, b.date_of_birth,
		       b.created_at, b.updated_at, b.deleted_at
		FROM   users a
		JOIN   users b ON b.id > a.id AND a.email = b.email
		WHERE  a.deleted_at IS NULL AND b.deleted_at IS NULL
		ORDER  BY a.id`

	exactRows, err := r.db.Query(exactQ)
	if err != nil {
		return nil, fmt.Errorf("repository: FindDuplicateUsers (exact): %w", err)
	}
	pairs, err := scanUserPairs(exactRows)
	if err != nil {
		return nil, fmt.Errorf("repository: FindDuplicateUsers (exact scan): %w", err)
	}
	for i := range pairs {
		pairs[i].Score = 1.0
	}

	// ---- Pass 2: same DOB candidates — fuzzy username match via Levenshtein ----
	const dobQ = `
		SELECT a.id, a.username, a.email, a.password_hash, a.role,
		       a.failed_attempts, a.locked_until, a.date_of_birth,
		       a.created_at, a.updated_at, a.deleted_at,
		       b.id, b.username, b.email, b.password_hash, b.role,
		       b.failed_attempts, b.locked_until, b.date_of_birth,
		       b.created_at, b.updated_at, b.deleted_at
		FROM   users a
		JOIN   users b ON b.id > a.id
		             AND a.date_of_birth IS NOT NULL
		             AND a.date_of_birth = b.date_of_birth
		             AND a.email != b.email
		WHERE  a.deleted_at IS NULL AND b.deleted_at IS NULL
		ORDER  BY a.id`

	dobRows, err := r.db.Query(dobQ)
	if err != nil {
		return nil, fmt.Errorf("repository: FindDuplicateUsers (dob): %w", err)
	}
	dobCandidates, err := scanUserPairs(dobRows)
	if err != nil {
		return nil, fmt.Errorf("repository: FindDuplicateUsers (dob scan): %w", err)
	}

	// Compute Levenshtein similarity for each same-DOB pair; keep if score ≥ 0.6.
	const fuzzyThreshold = 0.6
	for _, p := range dobCandidates {
		score := usernameSimilarity(p.UserA.Username, p.UserB.Username)
		if score >= fuzzyThreshold {
			p.Score = score
			pairs = append(pairs, p)
		}
	}

	// Sort by score descending, apply limit.
	sortDuplicatePairs(pairs)
	if limit > 0 && len(pairs) > limit {
		pairs = pairs[:limit]
	}
	return pairs, nil
}

// ---------------------------------------------------------------
// Duplicate-detection helpers
// ---------------------------------------------------------------

// scanUserPairs scans rows produced by a self-join query that returns two
// consecutive user column sets (without a score column).
func scanUserPairs(rows *sql.Rows) ([]DuplicatePair, error) {
	defer rows.Close()
	var pairs []DuplicatePair
	for rows.Next() {
		var p DuplicatePair
		a, b := &p.UserA, &p.UserB
		if err := rows.Scan(
			&a.ID, &a.Username, &a.Email, &a.PasswordHash, &a.Role,
			&a.FailedAttempts, &a.LockedUntil, &a.DateOfBirth,
			&a.CreatedAt, &a.UpdatedAt, &a.DeletedAt,
			&b.ID, &b.Username, &b.Email, &b.PasswordHash, &b.Role,
			&b.FailedAttempts, &b.LockedUntil, &b.DateOfBirth,
			&b.CreatedAt, &b.UpdatedAt, &b.DeletedAt,
		); err != nil {
			return nil, err
		}
		pairs = append(pairs, p)
	}
	return pairs, rows.Err()
}

// usernameSimilarity returns a 0–1 Levenshtein-based similarity score for two
// usernames (case-insensitive).
func usernameSimilarity(a, b string) float64 {
	a = strings.ToLower(a)
	b = strings.ToLower(b)
	maxLen := len(a)
	if len(b) > maxLen {
		maxLen = len(b)
	}
	if maxLen == 0 {
		return 1.0
	}
	dist := levenshtein(a, b)
	return 1.0 - float64(dist)/float64(maxLen)
}

// levenshtein computes the edit distance between two strings using the
// standard dynamic-programming approach.
func levenshtein(a, b string) int {
	ra, rb := []rune(a), []rune(b)
	la, lb := len(ra), len(rb)
	if la == 0 {
		return lb
	}
	if lb == 0 {
		return la
	}
	// Use two rows of the DP table to save memory.
	prev := make([]int, lb+1)
	curr := make([]int, lb+1)
	for j := 0; j <= lb; j++ {
		prev[j] = j
	}
	for i := 1; i <= la; i++ {
		curr[0] = i
		for j := 1; j <= lb; j++ {
			cost := 1
			if ra[i-1] == rb[j-1] {
				cost = 0
			}
			curr[j] = minInt(
				curr[j-1]+1,        // insertion
				prev[j]+1,          // deletion
				prev[j-1]+cost,     // substitution
			)
		}
		prev, curr = curr, prev
	}
	return prev[lb]
}

func minInt(a, b, c int) int {
	if a < b {
		if a < c {
			return a
		}
		return c
	}
	if b < c {
		return b
	}
	return c
}

// sortDuplicatePairs sorts pairs by Score descending (insertion sort — small N).
func sortDuplicatePairs(pairs []DuplicatePair) {
	for i := 1; i < len(pairs); i++ {
		key := pairs[i]
		j := i - 1
		for j >= 0 && pairs[j].Score < key.Score {
			pairs[j+1] = pairs[j]
			j--
		}
		pairs[j+1] = key
	}
}"}

