// scanUserPairs scans rows produced by a self-join query that returns two
// consecutive user column sets (without a score column).
func scanUserPairs(rows *sql.Rows) ([]DuplicatePair, error) {
	defer rows.Close()
	var pairs []DuplicatePair
	for rows.Next() {
		var p DuplicatePair
		a, b := &p.UserA, &p.UserB
		if err := rows.Scan(
			&a.ID, &a.Username, &a.Email, &a.PasswordHash, &a.Role,
			&a.FailedAttempts, &a.LockedUntil, &a.DateOfBirth,
			&a.CreatedAt, &a.UpdatedAt, &a.DeletedAt,
			&b.ID, &b.Username, &b.Email, &b.PasswordHash, &b.Role,
			&b.FailedAttempts, &b.LockedUntil, &b.DateOfBirth,
			&b.CreatedAt, &b.UpdatedAt, &b.DeletedAt,
		); err != nil {
			return nil, err
		}
		pairs = append(pairs, p)
	}
	return pairs, rows.Err()
}

// usernameSimilarity returns a 0–1 Levenshtein-based similarity score for two
// usernames (case-insensitive).
func usernameSimilarity(a, b string) float64 {
	a = strings.ToLower(a)
	b = strings.ToLower(b)
	maxLen := len(a)
	if len(b) > maxLen {
		maxLen = len(b)
	}
	if maxLen == 0 {
		return 1.0
	}
	dist := levenshtein(a, b)
	return 1.0 - float64(dist)/float64(maxLen)
}

// levenshtein computes the edit distance between two strings using the
// standard dynamic-programming approach.
func levenshtein(a, b string) int {
	ra, rb := []rune(a), []rune(b)
	la, lb := len(ra), len(rb)
	if la == 0 {
		return lb
	}
	if lb == 0 {
		return la
	}
	// Use two rows of the DP table to save memory.
	prev := make([]int, lb+1)
	curr := make([]int, lb+1)
	for j := 0; j <= lb; j++ {
		prev[j] = j
	}
	for i := 1; i <= la; i++ {
		curr[0] = i
		for j := 1; j <= lb; j++ {
			cost := 1
			if ra[i-1] == rb[j-1] {
				cost = 0
			}
			curr[j] = minInt(
				curr[j-1]+1,        // insertion
				prev[j]+1,          // deletion
				prev[j-1]+cost,     // substitution
			)
		}
		prev, curr = curr, prev
	}
	return prev[lb]
}

func minInt(a, b, c int) int {
	if a < b {
		if a < c {
			return a
		}
		return c
	}
	if b < c {
		return b
	}
	return c
}

// sortDuplicatePairs sorts pairs by Score descending (insertion sort — small N).
func sortDuplicatePairs(pairs []DuplicatePair) {
	for i := 1; i < len(pairs); i++ {
		key := pairs[i]
		j := i - 1
		for j >= 0 && pairs[j].Score < key.Score {
			pairs[j+1] = pairs[j]
			j--
		}
		pairs[j+1] = key
	}
}"}

