1	package crypto
2	
3	import (
4		"crypto/aes"
5		"crypto/cipher"
6		"crypto/rand"
7		"encoding/base64"
8		"errors"
9		"fmt"
10		"io"
11		"strings"
12		"unicode/utf8"
13	
14		"golang.org/x/crypto/bcrypt"
15	)
16	
17	// EncryptField encrypts plaintext using AES-256-GCM with the supplied 32-byte
18	// key.  The nonce is prepended to the ciphertext and the whole thing is
19	// returned as standard base64 so it is safe to store in a TEXT column.
20	func EncryptField(key []byte, plaintext string) (string, error) {
21		if len(key) != 32 {
22			return "", fmt.Errorf("crypto: encryption key must be 32 bytes, got %d", len(key))
23		}
24	
25		block, err := aes.NewCipher(key)
26		if err != nil {
27			return "", fmt.Errorf("crypto: create cipher: %w", err)
28		}
29	
30		gcm, err := cipher.NewGCM(block)
31		if err != nil {
32			return "", fmt.Errorf("crypto: create GCM: %w", err)
33		}
34	
35		nonce := make([]byte, gcm.NonceSize())
36		if _, err := io.ReadFull(rand.Reader, nonce); err != nil {
37			return "", fmt.Errorf("crypto: generate nonce: %w", err)
38		}
39	
40		// Seal appends the ciphertext+tag to nonce.
41		ciphertext := gcm.Seal(nonce, nonce, []byte(plaintext), nil)
42		return base64.StdEncoding.EncodeToString(ciphertext), nil
43	}
44	
45	// DecryptField is the inverse of EncryptField.  It decodes the base64 blob,
46	// extracts the nonce, and returns the plaintext.
47	func DecryptField(key []byte, ciphertext string) (string, error) {
48		if len(key) != 32 {
49			return "", fmt.Errorf("crypto: encryption key must be 32 bytes, got %d", len(key))
50		}
51	
52		data, err := base64.StdEncoding.DecodeString(ciphertext)
53		if err != nil {
54			return "", fmt.Errorf("crypto: base64 decode: %w", err)
55		}
56	
57		block, err := aes.NewCipher(key)
58		if err != nil {
59			return "", fmt.Errorf("crypto: create cipher: %w", err)
60		}
61	
62		gcm, err := cipher.NewGCM(block)
63		if err != nil {
64			return "", fmt.Errorf("crypto: create GCM: %w", err)
65		}
66	
67		nonceSize := gcm.NonceSize()
68		if len(data) < nonceSize {
69			return "", errors.New("crypto: ciphertext too short")
70		}
71	
72		nonce, data := data[:nonceSize], data[nonceSize:]
73		plaintext, err := gcm.Open(nil, nonce, data, nil)
74		if err != nil {
75			return "", fmt.Errorf("crypto: decrypt: %w", err)
76		}
77	
78		return string(plaintext), nil
79	}
80	
81	// HashPassword hashes password using bcrypt at cost 12.
82	func HashPassword(password string) (string, error) {
83		hash, err := bcrypt.GenerateFromPassword([]byte(password), 12)
84		if err != nil {
85			return "", fmt.Errorf("crypto: hash password: %w", err)
86		}
87		return string(hash), nil
88	}
89	
90	// CheckPassword returns true when password matches the stored bcrypt hash.
91	func CheckPassword(hash, password string) bool {
92		return bcrypt.CompareHashAndPassword([]byte(hash), []byte(password)) == nil
93	}
94	
95	// MaskName converts a full name into initials with a trailing period on each
96	// part.  Examples:
97	//
98	//	"John Doe"       → "J. D."
99	//	"Alice"          → "A."
100	//	"Mary Jane Watson" → "M. J. W."
101	//
102	// Empty input is returned unchanged.
103	func MaskName(name string) string {
104		name = strings.TrimSpace(name)
105		if name == "" {
106			return ""
107		}
108	
109		parts := strings.Fields(name)
110		var sb strings.Builder
111		for i, part := range parts {
112			r, size := utf8.DecodeRuneInString(part)
113			if size == 0 {
114				continue
115			}
116			_ = r
117			// Write just the first Unicode character of each word followed by ".".
118			sb.WriteString(string([]rune(part)[:1]))
119			sb.WriteByte('.')
120			if i < len(parts)-1 {
121				sb.WriteByte(' ')
122			}
123		}
124		return sb.String()
125	}
126	
127	// MaskID masks all but the last four characters of id with asterisks.
128	// Examples:
129	//
130	//	"1234567890"  → "******7890"
131	//	"AB12"        → "AB12"   (≤4 chars: returned as-is)
132	//	""            → ""
133	func MaskID(id string) string {
134		runes := []rune(id)
135		n := len(runes)
136		if n <= 4 {
137			return id
138		}
139		masked := make([]rune, n)
140		for i := 0; i < n-4; i++ {
141			masked[i] = '*'
142		}
143		copy(masked[n-4:], runes[n-4:])
144		return string(masked)
145	}
