// DuplicatePair represents two users that may be the same person.
type DuplicatePair struct {
	UserA models.User
	UserB models.User
	Score float64 // similarity 0-1
}

// FindDuplicateUsers returns user pairs that are likely the same person.
//
// Two detection strategies are applied independently:
//
//  1. Exact identifier match — same email address (the unique external identifier
//     in this system). Score = 1.0. Email is the closest analogue to a stable
//     government or student ID in the schema; any two accounts sharing the same
//     email are definitively the same person.
//
//  2. Fuzzy identity match — composite weighted score:
//
//       score = 0.6 × username_similarity  +  0.4 × dob_match
//
//     where username_similarity is the Levenshtein-based 0–1 similarity between
//     (lowercased) usernames (used as a name proxy when no dedicated name column
//     exists) and dob_match is 1.0 if both records have identical, non-null
//     date_of_birth values, 0.0 otherwise.
//
//     A pair is included when the combined score ≥ 0.65.  This threshold
//     ensures that neither signal alone is sufficient:
//       - DOB match only (0.4) → below threshold, excluded.
//       - Username similarity only (max 0.6) → at threshold only for identical
//         usernames; anything less is excluded unless DOB also matches.
//       - Both signals combined → reliably flag probable duplicates.
//
// SQL pre-filters candidates to pairs with either same DOB or same 4-char
// username prefix; Go scoring then applies the exact composite formula.
// Soft-deleted users are excluded. Results sorted by score desc, capped at limit.
func (r *AdminRepository) FindDuplicateUsers(limit int) ([]DuplicatePair, error) {
	// ---- Pass 1: exact identifier — same email address, score 1.0 ----
	const exactQ = `
		SELECT a.id, a.username, a.email, a.password_hash, a.role,
		       a.failed_attempts, a.locked_until, a.date_of_birth,
		       a.created_at, a.updated_at, a.deleted_at,
		       b.id, b.username, b.email, b.password_hash, b.role,
		       b.failed_attempts, b.locked_until, b.date_of_birth,
		       b.created_at, b.updated_at, b.deleted_at
		FROM   users a
		JOIN   users b ON b.id > a.id AND a.email = b.email
		WHERE  a.deleted_at IS NULL AND b.deleted_at IS NULL
		ORDER  BY a.id`

	exactRows, err := r.db.Query(exactQ)
	if err != nil {
		return nil, fmt.Errorf("repository: FindDuplicateUsers (exact): %w", err)
	}
	pairs, err := scanUserPairs(exactRows)
	if err != nil {
		return nil, fmt.Errorf("repository: FindDuplicateUsers (exact scan): %w", err)
	}
	for i := range pairs {
		pairs[i].Score = 1.0
	}

	// ---- Pass 2: fuzzy — composite(name similarity + DOB) ----
	// Pre-filter in SQL with OR logic to limit candidate set without
	// hard-coding which signal must match; Go computes the final score.
	const fuzzyQ = `
		SELECT a.id, a.username, a.email, a.password_hash, a.role,
		       a.failed_attempts, a.locked_until, a.date_of_birth,
		       a.created_at, a.updated_at, a.deleted_at,
		       b.id, b.username, b.email, b.password_hash, b.role,
		       b.failed_attempts, b.locked_until, b.date_of_birth,
		       b.created_at, b.updated_at, b.deleted_at
		FROM   users a
		JOIN   users b ON b.id > a.id
		             AND a.email != b.email
		WHERE  a.deleted_at IS NULL
		  AND  b.deleted_at IS NULL
		  AND (
		        (a.date_of_birth IS NOT NULL AND a.date_of_birth = b.date_of_birth)
		        OR LOWER(SUBSTR(a.username,1,4)) = LOWER(SUBSTR(b.username,1,4))
		      )
		ORDER  BY a.id`

	fuzzyRows, err := r.db.Query(fuzzyQ)
	if err != nil {
		return nil, fmt.Errorf("repository: FindDuplicateUsers (fuzzy): %w", err)
	}
	candidates, err := scanUserPairs(fuzzyRows)
	if err != nil {
		return nil, fmt.Errorf("repository: FindDuplicateUsers (fuzzy scan): %w", err)
	}

	// Score each candidate with the composite formula and apply threshold.
	const (
		nameWeight  = 0.6
		dobWeight   = 0.4
		minScore    = 0.65
	)
	for _, p := range candidates {
		nameSim := usernameSimilarity(p.UserA.Username, p.UserB.Username)
		var dobSim float64
		if p.UserA.DateOfBirth != nil && p.UserB.DateOfBirth != nil &&
			*p.UserA.DateOfBirth == *p.UserB.DateOfBirth {
			dobSim = 1.0
		}
		score := nameWeight*nameSim + dobWeight*dobSim
		if score >= minScore {
			p.Score = score
			pairs = append(pairs, p)
		}
	}

	// Sort by score descending, apply limit.
	sortDuplicatePairs(pairs)
	if limit > 0 && len(pairs) > limit {
		pairs = pairs[:limit]
	}
	return pairs, nil
}

// ---------------------------------------------------------------
// Duplicate-detection helpers
// ---------------------------------------------------------------

// scanUserPairs scans rows produced by a self-join query that returns two
// consecutive user column sets (without a score column).
func scanUserPairs(rows *sql.Rows) ([]DuplicatePair, error) {
	defer rows.Close()
	var pairs []DuplicatePair
	for rows.Next() {
		var p DuplicatePair
		a, b := &p.UserA, &p.UserB
		if err := rows.Scan(
			&a.ID, &a.Username, &a.Email, &a.PasswordHash, &a.Role,
			&a.FailedAttempts, &a.LockedUntil, &a.DateOfBirth,
			&a.CreatedAt, &a.UpdatedAt, &a.DeletedAt,
