12	// seedOrder creates a user, an active material with 5 available qty, places an
13	// order, then patches the order's status to the requested value directly via
14	// SQL. Returns the order ID.
15	func seedOrder(t *testing.T, db *sql.DB, status string) int64 {
16		t.Helper()
17	
18		// Insert a user.
19		var userID int64
20		err := db.QueryRow(
21			`INSERT INTO users (username, email, password_hash, role)
22			 VALUES (?, ?, ?, ?)
23			 RETURNING id`,
24			fmt.Sprintf("user_%d", testSeq()), "u@example.com", "hash", "student",
25		).Scan(&userID)
26		if err != nil {
27			t.Fatalf("seedOrder: insert user: %v", err)
28		}
29	
30		// Insert a material with 5 available qty.
31		var matID int64
32		err = db.QueryRow(
33			`INSERT INTO materials (title, total_qty, available_qty, reserved_qty, status)
34			 VALUES ('Test Book', 5, 5, 0, 'active')
35			 RETURNING id`,
36		).Scan(&matID)
37		if err != nil {
38			t.Fatalf("seedOrder: insert material: %v", err)
39		}
40	
41		// Place the order (status = pending_payment, inventory reserved).
42		orderRepo := repository.NewOrderRepository(db)
43		order, err := orderRepo.Create(userID, []repository.OrderItemInput{
44			{MaterialID: matID, Qty: 1},
45		})
46		if err != nil {
47			t.Fatalf("seedOrder: create order: %v", err)
48		}
49	
50		// Patch status if different from pending_payment.
51		if status != "pending_payment" {
52			// We manipulate status directly so we can seed any starting state.
53			// Also update auto_close_at appropriately.
54			var autoCloseExpr string
55			switch status {
56			case "pending_shipment":
57				autoCloseExpr = "datetime('now', '+72 hours')"
58			default:
59				autoCloseExpr = "NULL"
60			}
61			_, err = db.Exec(
62				fmt.Sprintf(`UPDATE orders SET status = ?, auto_close_at = %s WHERE id = ?`, autoCloseExpr),
63				status, order.ID,
64			)
65			if err != nil {
66				t.Fatalf("seedOrder: patch status: %v", err)
67			}
68	
69			// If seeding a non-pending_payment status the inventory has already been
70			// reserved by Create; for in_transit/completed we leave reserved_qty as-is
71			// (sufficient for the transition tests).
72		}
73	
74		return order.ID
