17	// makeRLApp builds a minimal Fiber app protected by a RateLimiter.
18	// keyFn extracts the rate-limit key from the request.
19	func makeRLApp(limit int, window time.Duration, keyFn func(*fiber.Ctx) string) *fiber.App {
20		app := fiber.New(fiber.Config{DisableStartupMessage: true})
21		rl := middleware.NewRateLimiter(limit, window)
22		app.Use(rl.Middleware(keyFn))
23		app.Get("/", func(c *fiber.Ctx) error {
24			return c.SendString("ok")
25		})
26		return app
27	}
28	
29	// fixedKeyApp is a convenience wrapper: every request uses the same key.
30	func fixedKeyApp(limit int, window time.Duration, key string) *fiber.App {
31		return makeRLApp(limit, window, func(_ *fiber.Ctx) string { return key })
32	}
33	
34	// headerKeyApp extracts the rate-limit key from the X-Key request header.
35	func headerKeyApp(limit int, window time.Duration) *fiber.App {
36		return makeRLApp(limit, window, func(c *fiber.Ctx) string { return c.Get("X-Key") })
37	}
38	
39	// rlGet fires a GET / against app and returns the HTTP status code.
40	func rlGet(t *testing.T, app *fiber.App) int {
41		t.Helper()
42		req := httptest.NewRequest("GET", "/", nil)
43		resp, err := app.Test(req, -1)
44		if err != nil {
45			t.Fatalf("app.Test: %v", err)
46		}
47		io.Copy(io.Discard, resp.Body) //nolint:errcheck
48		resp.Body.Close()
49		return resp.StatusCode
50	}
51	
52	// rlGetWithKey fires a GET / with the given X-Key header.
53	func rlGetWithKey(t *testing.T, app *fiber.App, key string) int {
54		t.Helper()
55		req := httptest.NewRequest("GET", "/", nil)
56		req.Header.Set("X-Key", key)
57		resp, err := app.Test(req, -1)
58		if err != nil {
59			t.Fatalf("app.Test: %v", err)
60		}
61		io.Copy(io.Discard, resp.Body) //nolint:errcheck
62		resp.Body.Close()
63		return resp.StatusCode
64	}
