70	// TestRateLimit_UnderLimit_AllAllowed: 4 requests with limit=5 → all pass.
71	func TestRateLimit_UnderLimit_AllAllowed(t *testing.T) {
72		app := fixedKeyApp(5, time.Minute, "under-limit")
73	
74		for i := 1; i <= 4; i++ {
75			if code := rlGet(t, app); code != fiber.StatusOK {
76				t.Errorf("request %d: expected 200, got %d", i, code)
77			}
78		}
79	}
80	
81	// TestRateLimit_AtLimit_FifthBlocked: with limit=4, the 5th request is blocked.
82	// The sliding-window limiter blocks when len(valid) >= limit, so after 4
83	// requests fill the window the 5th is rejected.
84	func TestRateLimit_AtLimit_FifthBlocked(t *testing.T) {
85		app := fixedKeyApp(4, time.Minute, "fifth-blocked")
86	
87		// First 4 must pass.
88		for i := 1; i <= 4; i++ {
89			if code := rlGet(t, app); code != fiber.StatusOK {
90				t.Errorf("request %d: expected 200, got %d", i, code)
91			}
92		}
93		// 5th must be blocked.
94		if code := rlGet(t, app); code != fiber.StatusTooManyRequests {
95			t.Errorf("5th request: expected 429, got %d", code)
96		}
97	}
98	
99	// TestRateLimit_BeyondLimit_AllSubsequentBlocked: after the limit is exhausted
100	// every additional request is rejected.
101	func TestRateLimit_BeyondLimit_AllSubsequentBlocked(t *testing.T) {
102		app := fixedKeyApp(3, time.Minute, "beyond-limit")
103	
104		// Exhaust the limit (3 requests pass, 4th is blocked).
105		for i := 1; i <= 3; i++ {
106			rlGet(t, app)
107		}
108	
109		for i := 4; i <= 6; i++ {
110			if code := rlGet(t, app); code != fiber.StatusTooManyRequests {
111				t.Errorf("request %d: expected 429, got %d", i, code)
112			}
113		}
114	}
115	
116	// TestRateLimit_DifferentKeys_Independent: hitting the limit on key A does not
117	// affect key B.
118	func TestRateLimit_DifferentKeys_Independent(t *testing.T) {
119		app := headerKeyApp(3, time.Minute)
120	
121		// Exhaust limit for key A.
122		for i := 0; i < 3; i++ {
123			rlGetWithKey(t, app, "key-a")
124		}
125		// Key A should now be blocked.
126		if code := rlGetWithKey(t, app, "key-a"); code != fiber.StatusTooManyRequests {
127			t.Errorf("key-a: expected 429, got %d", code)
128		}
129		// Key B is independent — should be allowed.
130		if code := rlGetWithKey(t, app, "key-b"); code != fiber.StatusOK {
131			t.Errorf("key-b: expected 200 (independent), got %d", code)
132		}
133	}
