135	// TestRateLimit_WindowExpiry_ResetsCounter: after the window expires the
136	// counter resets and requests are allowed again.
137	func TestRateLimit_WindowExpiry_ResetsCounter(t *testing.T) {
138		app := fixedKeyApp(3, 50*time.Millisecond, "expiry-key")
139	
140		// Fill the window.
141		for i := 0; i < 3; i++ {
142			rlGet(t, app)
143		}
144		if code := rlGet(t, app); code != fiber.StatusTooManyRequests {
145			t.Errorf("before expiry: expected 429, got %d", code)
146		}
147	
148		// Wait for the window to expire.
149		time.Sleep(60 * time.Millisecond)
150	
151		// Should be allowed again.
152		if code := rlGet(t, app); code != fiber.StatusOK {
153			t.Errorf("after window expiry: expected 200, got %d", code)
154		}
155	}
