117		// Reserving 0 — the WHERE clause requires available_qty >= qty (0),
118		// which is always true, so rows may be affected. The real semantic
119		// constraint is that qty must be positive. The service layer enforces
120		// this, but we verify the repository does not crash.
121		err := matRepo.Reserve(id, 0)
122		// Reserving 0 is a no-op in the DB (WHERE available_qty >= 0 is always
123		// satisfied and the SET is a no-op), so we check that at least the
124		// quantities haven't changed meaningfully.
125		avail, rsv := getMaterialQtys(t, db, id)
126		if err == nil {
127			// Accepted — values must be unchanged.
128			if avail != 5 || rsv != 0 {
129				t.Errorf("Reserve(0) changed qtys: avail=%d rsv=%d", avail, rsv)
130			}
131		}
132		// Whether err==nil or not, this is acceptable behavior; the key check
133		// is that no panic occurred and data integrity is maintained.
134	}
