412	
413	// TestInventory_PostFulfillment_Return_ReservedNonNegative exercises the full
414	// order → complete → return path and asserts that reserved_qty never goes
415	// negative at any point.
416	func TestInventory_PostFulfillment_Return_ReservedNonNegative(t *testing.T) {
417		db := testutil.NewTestDBNoFK(t)
418		orderRepo := repository.NewOrderRepository(db)
419		matRepo := repository.NewMaterialRepository(db)
420	
421		// Seed user and material.
422		var userID int64
423		if err := db.QueryRow(
424			`INSERT INTO users (username, email, password_hash, role) VALUES (?, 'ret@x.com', 'h', 'student') RETURNING id`,
425			fmt.Sprintf("ret_user_%d", testSeq()),
426		).Scan(&userID); err != nil {
427			t.Fatalf("insert user: %v", err)
428		}
429		var matID int64
430		if err := db.QueryRow(
431			`INSERT INTO materials (title, total_qty, available_qty, reserved_qty, status)
432			 VALUES ('Return Book', 5, 5, 0, 'active') RETURNING id`,
433		).Scan(&matID); err != nil {
434			t.Fatalf("insert material: %v", err)
435		}
436	
437		// Place order (reserves 2 units: available 3, reserved 2).
438		order, err := orderRepo.Create(userID, []repository.OrderItemInput{
439			{MaterialID: matID, Qty: 2},
440		})
441		if err != nil {
442			t.Fatalf("Create order: %v", err)
443		}
444		avail, rsv := getMaterialQtys(t, db, matID)
445		if avail != 3 || rsv != 2 {
446			t.Fatalf("after order: avail=%d rsv=%d (want 3/2)", avail, rsv)
447		}
448	
449		// Transition through the lifecycle to completed.
450		if err := orderRepo.Transition(order.ID, userID, "pending_shipment", "paid", matRepo); err != nil {
451			t.Fatalf("→ pending_shipment: %v", err)
452		}
453		if err := orderRepo.Transition(order.ID, userID, "in_transit", "shipped", matRepo); err != nil {
454			t.Fatalf("→ in_transit: %v", err)
455		}
456		if err := orderRepo.Transition(order.ID, userID, "completed", "delivered", matRepo); err != nil {
457			t.Fatalf("→ completed: %v", err)
458		}
459	
460		// After completion: reserved_qty decremented to 0, available unchanged (3).
461		avail, rsv = getMaterialQtys(t, db, matID)
462		if rsv != 0 {
463			t.Fatalf("after completion: reserved_qty=%d (want 0)", rsv)
464		}
465		if avail != 3 {
466			t.Fatalf("after completion: available_qty=%d (want 3)", avail)
467		}
468	
469		// Post-fulfillment return: ReturnToStock must add to available, not touch reserved.
470		if err := matRepo.ReturnToStock(matID, 2); err != nil {
471			t.Fatalf("ReturnToStock: %v", err)
472		}
473		avail, rsv = getMaterialQtys(t, db, matID)
474		if rsv < 0 {
475			t.Errorf("INVARIANT VIOLATED: reserved_qty went negative after post-fulfillment return: %d", rsv)
476		}
477		if rsv != 0 {
478			t.Errorf("reserved_qty should still be 0 after return, got %d", rsv)
479		}
480		if avail != 5 {
481			t.Errorf("available_qty should be 5 after return, got %d", avail)
482		}
483	}
