485	// TestInventory_PostFulfillment_Exchange_ReservedNonNegative exercises the
486	// exchange path: old copy returned (ReturnToStock) + new copy direct-issued
487	// (DirectIssue). reserved_qty must remain non-negative throughout.
488	func TestInventory_PostFulfillment_Exchange_ReservedNonNegative(t *testing.T) {
489		db := testutil.NewTestDBNoFK(t)
490		matRepo := repository.NewMaterialRepository(db)
491	
492		// Simulate post-fulfillment: old material has 0 reserved (fulfilled).
493		oldID := seedMaterial(t, db, 5, 3, 0)
494		// New material for exchange: has available stock.
495		newID := seedMaterial(t, db, 5, 5, 0)
496	
497		// Old copy returned.
498		if err := matRepo.ReturnToStock(oldID, 1); err != nil {
499			t.Fatalf("ReturnToStock old: %v", err)
500		}
501		// New copy directly issued.
502		if err := matRepo.DirectIssue(newID, 1); err != nil {
503			t.Fatalf("DirectIssue new: %v", err)
504		}
505	
506		_, oldRsv := getMaterialQtys(t, db, oldID)
507		_, newRsv := getMaterialQtys(t, db, newID)
508	
509		if oldRsv < 0 {
510			t.Errorf("INVARIANT VIOLATED: old material reserved_qty=%d (negative after exchange return)", oldRsv)
511		}
512		if newRsv < 0 {
513			t.Errorf("INVARIANT VIOLATED: new material reserved_qty=%d (negative after exchange issue)", newRsv)
514		}
515	}
