287	// ---------------------------------------------------------------------------
288	
289	// TestAuth_SessionHash_DependsOnSecret verifies that the token hash stored in
290	// the sessions table is HMAC-keyed with SESSION_SECRET, not a bare SHA-256.
291	// A hash computed with a different secret must not match any DB row, so an
292	// attacker who knows the raw token but not the secret cannot construct a valid
293	// session hash.
294	func TestAuth_SessionHash_DependsOnSecret(t *testing.T) {
295		const correctSecret = "correct-session-secret-for-test"
296		const wrongSecret   = "attacker-does-not-know-real-secret"
297	
298		db := testutil.NewTestDB(t)
299		userRepo    := repository.NewUserRepository(db)
300		sessionRepo := repository.NewSessionRepository(db)
301		cfg         := &config.Config{SessionSecret: correctSecret}
302		svc         := services.NewAuthService(userRepo, sessionRepo, cfg)
303	
304		if _, err := svc.Register("hmacuser", "hmac@x.com", "password12345", "student"); err != nil {
305			t.Fatalf("register: %v", err)
306		}
307	
308		token, _, err := svc.Login("hmacuser", "password12345")
309		if err != nil {
310			t.Fatalf("login: %v", err)
311		}
312	
313		// A hash computed with the WRONG secret must not find the session.
314		wrongHash := hashTokenForTest(wrongSecret, token)
315		var wrongCount int
316		if err := db.QueryRow(
317			`SELECT COUNT(*) FROM sessions WHERE token_hash = ?`, wrongHash,
318		).Scan(&wrongCount); err != nil {
319			t.Fatalf("count (wrong secret): %v", err)
320		}
321		if wrongCount != 0 {
322			t.Error("session was found using a hash computed with the WRONG secret — HMAC key is not enforced")
323		}
324	
325		// A hash computed with the CORRECT secret must find exactly one session.
326		correctHash := hashTokenForTest(correctSecret, token)
327		var correctCount int
328		if err := db.QueryRow(
329			`SELECT COUNT(*) FROM sessions WHERE token_hash = ?`, correctHash,
330		).Scan(&correctCount); err != nil {
331			t.Fatalf("count (correct secret): %v", err)
332		}
333		if correctCount != 1 {
334			t.Errorf("expected 1 session with correct secret hash, got %d", correctCount)
335		}
336	}
