14	// TestRegionStats_CorrectAggregation verifies that RegionStats produces
15	// per-region counts that correctly reflect only events whose custody names
16	// match nearby locations, not a cross-join total.
17	//
18	// Setup:
19	//   - Region A at (0.0, 0.0)  — depot "Depot-A" at (0.1, 0.1) is within 50 km
20	//   - Region B at (10.0, 10.0) — depot "Depot-B" at (10.1, 10.1) is within 50 km
21	//   - 2 distribution events referencing Depot-A (custody_to = "Depot-A")
22	//   - 1 distribution event referencing Depot-B
23	//
24	// Expected: region A = 2 scans, region B = 1 scan; no cross-contamination.
25	func TestRegionStats_CorrectAggregation(t *testing.T) {
26		db := testutil.NewTestDB(t)
27	
28		// Insert region centroids.
29		if _, err := db.Exec(`INSERT INTO locations (name, type, lat, lng) VALUES ('Region-A', 'admin_region', 0.0, 0.0)`); err != nil {
30			t.Fatalf("insert Region-A: %v", err)
31		}
32		if _, err := db.Exec(`INSERT INTO locations (name, type, lat, lng) VALUES ('Region-B', 'admin_region', 10.0, 10.0)`); err != nil {
33			t.Fatalf("insert Region-B: %v", err)
34		}
35		// Insert depot locations (non-region, within 50 km of their respective regions).
36		if _, err := db.Exec(`INSERT INTO locations (name, type, lat, lng) VALUES ('Depot-A', 'depot', 0.1, 0.1)`); err != nil {
37			t.Fatalf("insert Depot-A: %v", err)
38		}
39		if _, err := db.Exec(`INSERT INTO locations (name, type, lat, lng) VALUES ('Depot-B', 'depot', 10.1, 10.1)`); err != nil {
40			t.Fatalf("insert Depot-B: %v", err)
41		}
42	
43		// Insert a material and two orders.
44		var matID, orderID1, orderID2 int64
45		if err := db.QueryRow(`INSERT INTO materials (title, total_qty, available_qty, reserved_qty, status) VALUES ('Book', 10, 10, 0, 'active') RETURNING id`).Scan(&matID); err != nil {
46			t.Fatalf("insert material: %v", err)
47		}
48		var userID int64
49		if err := db.QueryRow(`INSERT INTO users (username, email, password_hash, role) VALUES ('u1','u1@x.com','$2a$12$x','student') RETURNING id`).Scan(&userID); err != nil {
50			t.Fatalf("insert user: %v", err)
51		}
52		if err := db.QueryRow(`INSERT INTO orders (user_id, status, total_amount, auto_close_at, created_at, updated_at) VALUES (?, 'completed', 0, datetime('now'), datetime('now'), datetime('now')) RETURNING id`, userID).Scan(&orderID1); err != nil {
53			t.Fatalf("insert order1: %v", err)
54		}
55		if err := db.QueryRow(`INSERT INTO orders (user_id, status, total_amount, auto_close_at, created_at, updated_at) VALUES (?, 'completed', 0, datetime('now'), datetime('now'), datetime('now')) RETURNING id`, userID).Scan(&orderID2); err != nil {
56			t.Fatalf("insert order2: %v", err)
57		}
58	
59		// 2 events for Region-A depot, 1 event for Region-B depot.
60		insEvent := func(orderID int64, custodyTo string) {
61			t.Helper()
62			if _, err := db.Exec(`INSERT INTO distribution_events (order_id, material_id, qty, event_type, actor_id, custody_to, occurred_at) VALUES (?, ?, 1, 'issue', ?, ?, datetime('now'))`, orderID, matID, userID, custodyTo); err != nil {
63				t.Fatalf("insert event custody_to=%s: %v", custodyTo, err)
64			}
65		}
66		insEvent(orderID1, "Depot-A")
67		insEvent(orderID1, "Depot-A") // second event same order
68		insEvent(orderID2, "Depot-B")
69	
70		repo := repository.NewAnalyticsRepository(db)
71		stats, err := repo.RegionStats()
72		if err != nil {
73			t.Fatalf("RegionStats: %v", err)
74		}
75	
76		byName := make(map[string]struct {
77			orders, scans int
78		})
79		for _, s := range stats {
80			byName[s.RegionName] = struct{ orders, scans int }{s.OrderCount, s.ScanCount}
81		}
82	
83		// Region A should have 2 scans from 1 distinct order.
84		if a, ok := byName["Region-A"]; !ok {
85			t.Fatal("Region-A not found in stats")
86		} else {
87			if a.scans != 2 {
88				t.Errorf("Region-A: expected 2 scans, got %d", a.scans)
89			}
90			if a.orders != 1 {
91				t.Errorf("Region-A: expected 1 order, got %d", a.orders)
92			}
93		}
94	
95		// Region B should have 1 scan from 1 distinct order.
96		if b, ok := byName["Region-B"]; !ok {
97			t.Fatal("Region-B not found in stats")
98		} else {
99			if b.scans != 1 {
100				t.Errorf("Region-B: expected 1 scan, got %d", b.scans)
101			}
102			if b.orders != 1 {
103				t.Errorf("Region-B: expected 1 order, got %d", b.orders)
104			}
105		}
106	
107		// Crucially: Region A must NOT have Region B's counts (no cross-join).
108		if a, b := byName["Region-A"], byName["Region-B"]; a.scans == a.scans+b.scans {
109			t.Errorf("cross-join detected: Region-A scan count (%d) equals total (%d)", a.scans, a.scans+b.scans)
110		}
111	}
