113	// TestSpatialAggregates_Query_Under200ms verifies the checklist requirement:
114	// "Spatial aggregate query returns in <200ms on 10k rows."
115	//
116	// It inserts 10 000 spatial_aggregates rows for a single layer_type, then
117	// times a GetSpatialAggregates call and fails if it exceeds 200 ms.
118	func TestSpatialAggregates_Query_Under200ms(t *testing.T) {
119		db := testutil.NewTestDB(t)
120		repo := repository.NewAnalyticsRepository(db)
121	
122		const (
123			n         = 10_000
124			layerType = "school"
125			metric    = "count"
126			limit     = 200 * time.Millisecond
127		)
128	
129		// Bulk-insert 10k rows via a transaction for speed.
130		tx, err := db.Begin()
131		if err != nil {
132			t.Fatalf("begin tx: %v", err)
133		}
134		stmt, err := tx.Prepare(`
135			INSERT INTO spatial_aggregates (layer_type, cell_key, metric, value, computed_at)
136			VALUES (?, ?, ?, ?, datetime('now'))
137			ON CONFLICT(layer_type, cell_key, metric) DO NOTHING`)
138		if err != nil {
139			tx.Rollback() //nolint:errcheck
140			t.Fatalf("prepare: %v", err)
141		}
142		for i := 0; i < n; i++ {
143			cellKey := fmt.Sprintf("cell_%06d", i)
144			if _, err := stmt.Exec(layerType, cellKey, metric, float64(i)); err != nil {
145				stmt.Close()
146				tx.Rollback() //nolint:errcheck
147				t.Fatalf("insert row %d: %v", i, err)
148			}
149		}
150		stmt.Close()
